def parse_duration(text):
    text = text.strip()
    hours = 0
    minutes = 0

    if 'h' in text:
        h_index = text.find('h')
        hours = int(text[:h_index])
        if h_index + 1 < len(text) and text[h_index + 1] == 'm':
            m_start = h_index + 2
            while m_start < len(text) and text[m_start].isdigit():
                m_start += 1
            if m_start > h_index + 2:
                minutes = int(text[h_index + 2:m_start])

    elif 'm' in text:
        m_index = text.find('m')
        minutes = int(text[:m_index])

    else:
        for i, char in enumerate(text):
            if char.isdigit():
                continue
            else:
                break
        if i > 0:
            hours = int(text[:i])

    return hours * 60 + minutes

