def parse_duration(text):
    text = text.strip()
    hours = 0
    minutes = 0

    # Split by whitespace and process each part
    parts = text.split()

    for part in parts:
        if part.endswith('h'):
            hours = int(part[:-1])
        elif part.endswith('m'):
            minutes = int(part[:-1])

    return hours * 60 + minutes

