def mask_tokens(text, secrets):
    # Sort secrets by length in descending order to handle longer ones first
    sorted_secrets = sorted(secrets, key=len, reverse=True)

    for secret in sorted_secrets:
        text = text.replace(secret, '[MASK]')

    return text
